import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as r,f as i}from"./app-f83986bb.js";const o={},d=i('<h1 id="devops" tabindex="-1"><a class="header-anchor" href="#devops" aria-hidden="true">#</a> devops</h1><p><code>DevOps </code>强调的是高效组织团队之间如何通过自动化的工具协作和沟通来完成软件的生命周期管理， <code>从而更快、更频繁地交付更稳定的软件</code>。</p><ul><li>development</li><li>operation</li><li>quality assurance</li></ul><h2 id="ci-cd-流水线" tabindex="-1"><a class="header-anchor" href="#ci-cd-流水线" aria-hidden="true">#</a> ci/cd 流水线</h2><p>核心: 自动化</p><blockquote><p>持续集成</p></blockquote><p>自动编译、构建打包、部署、测试。 根据测试结果，我们可以确定新代码和原有代码能否正确地集成在⼀起。</p><blockquote><p>持续交付</p></blockquote><p>频繁地将软件的新版本，交付给质量团队或者⽤户，以供评审。如果评审通过，代码就进⼊⽣产阶段。</p><blockquote><p>持续部署</p></blockquote><p>代码在任何时刻都是可部署的，可以进⼊⽣产阶段。 评审结束后，部署到生产环境</p><h2 id="自动化工具" tabindex="-1"><a class="header-anchor" href="#自动化工具" aria-hidden="true">#</a> 自动化工具</h2><h3 id="jenkins" tabindex="-1"><a class="header-anchor" href="#jenkins" aria-hidden="true">#</a> jenkins</h3><ul><li>拉取代码构建，打成jar包，构建镜像，推送到远程仓库(jenkinsFile实现持续集成)</li><li>svn拉取代码构建打jar包推送到gitlab仓库</li></ul><h3 id="gitlab" tabindex="-1"><a class="header-anchor" href="#gitlab" aria-hidden="true">#</a> gitlab</h3><p>根据提交记录自动触发 使用其内部集成的持续集成工具，构建镜像、部署、推送远程仓库</p><h3 id="docker-compose" tabindex="-1"><a class="header-anchor" href="#docker-compose" aria-hidden="true">#</a> docker-compose</h3><p>管理应用的多个容器，即应用容器化部署 启动，停止容器</p><h3 id="harbor" tabindex="-1"><a class="header-anchor" href="#harbor" aria-hidden="true">#</a> harbor</h3><p>远程镜像服务器 以项目形式管理镜像</p><h3 id="groovy-script" tabindex="-1"><a class="header-anchor" href="#groovy-script" aria-hidden="true">#</a> groovy script</h3><h3 id="jmeter压测" tabindex="-1"><a class="header-anchor" href="#jmeter压测" aria-hidden="true">#</a> jmeter压测</h3><h3 id="apifox" tabindex="-1"><a class="header-anchor" href="#apifox" aria-hidden="true">#</a> apiFox</h3>',23),h=[d];function c(t,n){return a(),r("div",null,h)}const p=e(o,[["render",c],["__file","Devops.html.vue"]]);export{p as default};
